// Modify the setupFileUpload function to handle edit mode properly
function setupFileUpload(inputId, fieldName, previewId) {
  const input = document.getElementById(inputId);
  if (!input) return;

  // Add progress bar if not present
  let progressBar = document.getElementById(`${inputId}-progress`);
  if (!progressBar) {
    progressBar = document.createElement('div');
    progressBar.id = `${inputId}-progress`;
    progressBar.style.display = 'none';
    progressBar.style.height = '8px';
    progressBar.style.background = '#d5d5d5';
    progressBar.innerHTML = '<div style="height:100%;width:0;background:#a31313;transition:width 0.2s;" class="progress-inner"></div>';
    input.parentNode.appendChild(progressBar);
  }

  input.addEventListener("change", function(e) {
    const files = e.target.files;
    if (!files.length) return;

    const form = document.getElementById('applicationForm');
    const formData = new FormData(form);
    formData.append('final_submission', '0');
    
    if (window.location.search.includes("edit_mode=1")) {
      formData.append('edit_mode', '1');
    }

    // Show progress bar
    progressBar.style.display = 'block';
    progressBar.querySelector('.progress-inner').style.width = '0';

    const xhr = new XMLHttpRequest();
    xhr.open('POST', 'save_application.php', true);

    xhr.upload.onprogress = function(event) {
      if (event.lengthComputable) {
        const percent = Math.round((event.loaded / event.total) * 100);
        progressBar.querySelector('.progress-inner').style.width = percent + '%';
      }
    };

    xhr.onload = function() {
      progressBar.style.display = 'none';
      if (xhr.status === 200) {
        try {
          const resp = JSON.parse(xhr.responseText);
          if (resp.success) {
            showMessageBox('Files uploaded successfully!', '#098d0d');
            
            // Clear the input to allow re-uploading same files
            input.value = '';
            
            // Only update from server state to avoid duplicates
            updateFilePreviews();
          } else {
            showMessageBox('Upload error: ' + (resp.message || 'Unknown error'), '#ff4444');
          }
        } catch (err) {
          showMessageBox('Upload failed: Invalid server response', '#ff4444');
        }
      } else {
        showMessageBox('Upload failed: Server error', '#ff4444');
      }
    };

    xhr.onerror = function() {
      progressBar.style.display = 'none';
      showMessageBox('Upload failed: Network error', '#ff4444');
    };

    xhr.send(formData);
  });
}

