document.addEventListener('DOMContentLoaded', function() {
    // Custom select with ratings functionality
    const customSelect = document.getElementById('custom-interest-select');
    if (customSelect) {
        const selectBtn = customSelect.querySelector('.select-btn');
        const listItems = customSelect.querySelector('.list-items');
        const btnText = selectBtn.querySelector('.btn-text');
        const hiddenInput = document.getElementById('interest-hidden');
        
        let selectedItems = [];

        // Initialize with checked items
        const items = customSelect.querySelectorAll('.item');
        items.forEach(item => {
            if (item.classList.contains('checked')) {
                selectedItems.push(item.getAttribute('data-value'));
            }
        });

        updateButtonText();
        updateHiddenInput();
        renderInterestRatings(selectedItems);

        // Toggle dropdown
        selectBtn.addEventListener('click', () => {
            listItems.classList.toggle('open');
            selectBtn.classList.toggle('open');
        });

        // Item selection
        items.forEach(item => {
            item.addEventListener('click', function(event) {
                event.stopPropagation();
                item.classList.toggle('checked');
                
                selectedItems = Array.from(customSelect.querySelectorAll('.item.checked'))
                    .map(el => el.getAttribute('data-value'));
                
                updateButtonText();
                updateHiddenInput();
                renderInterestRatings(selectedItems);
            });
        });

        // Close dropdown when clicking outside
        document.addEventListener('click', function(event) {
            if (!customSelect.contains(event.target)) {
                listItems.classList.remove('open');
                selectBtn.classList.remove('open');
            }
        });

        function updateButtonText() {
            btnText.textContent = selectedItems.length > 0 
                ? `${selectedItems.length} Selected` 
                : 'Select Fields';
        }

        function updateHiddenInput() {
            hiddenInput.value = selectedItems.join(',');
        }
    }
});

// Update the renderInterestRatings function to use the saved ratings:
function renderInterestRatings(interests) {
    const container = document.getElementById('interest-ratings');
    if (!container) return;

    container.innerHTML = '';
    
    interests.forEach(interest => {
        const safeId = interest.replace(/[^a-zA-Z0-9]/g, '_');
        // Default rating will be 5 if not found in savedRatings
        const ratingValue = savedRatings[interest] !== undefined ? 
            savedRatings[interest] : 5;
        
        container.innerHTML += `
            <div class="interest-rating-group" style="margin:10px 0;">
                <label style="font-weight:500;">
                    ${interest} self-rating: 
                    <span id="label-${safeId}" style="display:inline-block;margin-left:10px;">${ratingValue}</span>/10
                </label>
                <div class="slider-container" style="margin-top:5px;">
                    <input 
                        type="range" 
                        min="0" max="10" step="1" 
                        name="interest_ratings[${interest}]"
                        id="slider-${safeId}"
                        value="${ratingValue}"
                    >
                </div>
            </div>
        `;
    });

    styleInterestSliders(interests);
}
// Style the rating sliders
function styleInterestSliders(interests) {
    interests.forEach(interest => {
        const safeId = interest.replace(/[^a-zA-Z0-9]/g, '_');
        const slider = document.getElementById(`slider-${safeId}`);
        const label = document.getElementById(`label-${safeId}`);

        if (slider && label) {
            function updateSliderStyle() {
                const percentage = (slider.value / slider.max) * 100;
                slider.style.background = `linear-gradient(to right, #a31313 ${percentage}%, #d5d5d5 ${percentage}%)`;
                label.textContent = slider.value;
            }

            slider.addEventListener('input', updateSliderStyle);
            updateSliderStyle(); // Initial style
        }
    });
}

// Update updateFilePreviews function
function updateFilePreviews() {
  // Fetch the current file state from the server
  fetch('get_file_state.php')
    .then(response => response.json())
    .then(files => {
      // Update each preview section
      ['research', 'commented', 'additional'].forEach(type => {
        const previewId = `${type}-preview`;
        const previewElement = document.getElementById(previewId);
        if (previewElement) {
          previewElement.innerHTML = '';
          
          const fieldName = `${type}_files`;
          if (files[fieldName]) {
            files[fieldName].forEach((file, index) => {
              const fileElement = document.createElement('div');
              fileElement.className = 'uploaded-file';
              fileElement.dataset.fileName = file.name;
              fileElement.innerHTML = `
                <p><span>${formatFileSize(file.size)}</span> ${file.name}</p>
                <button type="button" class="remove" onclick="removeSavedFile('${fieldName}', ${index})">
                  <i class="fa-solid fa-trash"></i>
                </button>
              `;
              previewElement.appendChild(fileElement);
            });
          }
        }
      });
    })
    .catch(error => {
      console.error('Error updating file previews:', error);
    });
}